+func printForcedPushResult(fp *ForcedPushCheck) {
+	fmt.Println("1. Force Push Detection")
+	if fp.Detected {
+		fmt.Printf("   [PROBLEM] %s\n", fp.Message)
+	} else {
+		fmt.Printf("   [OK] %s\n", fp.Message)
+	}
+	fmt.Println()
+}
